        "high": subprocess.HIGH_PRIORITY_CLASS,
    }.get(self.process_priority)  # type: ignore[arg-type]

def _apply_unix_priority(self, pid: int) -> None:
    niceness = _UNIX_PRIORITY_NICENESS.get(self.process_priority)  # type: ignore[arg-type]

    if niceness is None:
        return

    try:
        os.setpriority(os.PRIO_PROCESS, pid, niceness)
    except (AttributeError, OSError, PermissionError):
        # Priority may not be adjustable (e.g. raising priority
        # without sufficient privileges). Fall back silently to
        # the default priority the process already has.
        pass

